import React, { useState } from 'react';
import { loginUser } from '../services/api';
import { useAuth } from '../context/AuthContext';

function Login() {
  // 3 cheezein yaad rakhni hain
  const [email, setEmail]       = useState('');
  const [password, setPassword] = useState('');
  const [error, setError]       = useState('');

  const { login } = useAuth(); // AuthContext se login function lo

  const handleSubmit = async (e) => {
    e.preventDefault(); // Page reload hone se rokta hai
    setError('');

    try {
      const res = await loginUser({ email, password }); // API call
      login(res.data.token, res.data.user); // Token save karo
      window.location.href = '/dashboard'; // Dashboard pe bhejo
    } catch (err) {
      setError(err.response?.data?.message || 'Login failed');
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h1 style={styles.logo}>🦉 DevNest</h1>
        <h2 style={styles.title}>Welcome back!</h2>

        {error && <p style={styles.error}>{error}</p>}

        <form onSubmit={handleSubmit}>
          <div style={styles.inputGroup}>
            <label style={styles.label}>Email</label>
            <input
              style={styles.input}
              type="email"
              placeholder="shrey@gmail.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
            />
          </div>

          <div style={styles.inputGroup}>
            <label style={styles.label}>Password</label>
            <input
              style={styles.input}
              type="password"
              placeholder="••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />
          </div>

          <button type="submit" style={styles.button}>
            Login →
          </button>
        </form>

        <p style={styles.link}>
          Account nahi hai? <a href="/register">Register karo</a>
        </p>
      </div>
    </div>
  );
}

// Styles — CSS in JS
const styles = {
  container: {
    minHeight: '100vh',
    background: '#0f0f0f',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
  },
  card: {
    background: '#1a1a1a',
    border: '1px solid #2a2a2a',
    borderRadius: '16px',
    padding: '40px',
    width: '100%',
    maxWidth: '400px',
  },
  logo: {
    textAlign: 'center',
    fontSize: '32px',
    marginBottom: '8px',
  },
  title: {
    textAlign: 'center',
    color: '#ffffff',
    fontSize: '20px',
    marginBottom: '24px',
    fontWeight: '400',
  },
  inputGroup: {
    marginBottom: '16px',
  },
  label: {
    display: 'block',
    color: '#888',
    fontSize: '13px',
    marginBottom: '6px',
  },
  input: {
    width: '100%',
    padding: '12px',
    background: '#0f0f0f',
    border: '1px solid #2a2a2a',
    borderRadius: '8px',
    color: '#ffffff',
    fontSize: '14px',
    outline: 'none',
    boxSizing: 'border-box',
  },
  button: {
    width: '100%',
    padding: '12px',
    background: '#22c55e',
    border: 'none',
    borderRadius: '8px',
    color: '#000000',
    fontSize: '15px',
    fontWeight: '600',
    cursor: 'pointer',
    marginTop: '8px',
  },
  error: {
    color: '#ef4444',
    fontSize: '13px',
    marginBottom: '16px',
    textAlign: 'center',
  },
  link: {
    textAlign: 'center',
    color: '#888',
    fontSize: '13px',
    marginTop: '20px',
  }
};

export default Login;
